public static long solve(long[] nums, long k) {
    int n = nums.length;
    long[] prefix_xor = new long[n + 1];
    for (int i = 1; i <= n; i++) {
        prefix_xor[i] = prefix_xor[i - 1] ^ nums[i - 1];
    }

    long[][] dp = new long[n + 1][k + 1];
    for (int i = 0; i <= n; i++) {
        for (int j = 0; j <= k; j++) {
            dp[i][j] = Long.MAX_VALUE;
        }
    }
    dp[0][0] = 0;

    for (int i = 1; i <= n; i++) {
        dp[i][1] = prefix_xor[i] ^ prefix_xor[0];
    }

    for (int j = 2; j <= k; j++) {
        for (int i = j; i <= n; i++) {
            for (int m = j - 1; m < i; m++) {
                long current_val = Math.max(dp[m][j - 1], prefix_xor[i] ^ prefix_xor[m]);
                if (current_val < dp[i][j]) {
                    dp[i][j] = current_val;
                }
            }
        }
    }

    return dp[n][k];
}
